// Stage 8.8.31 — workflow JSON dry-run flags (no $env; staging n8n blocks env in expressions)
const inbound = $input.first().json;
return [{
  json: {
    ...inbound,
    dry_run: true,
    live_send_enabled: false
  }
}];

// Stage 8.8.31 — parse inbound guest add-on request + deterministic idempotency_key
const root = $input.first().json;
const body = root.body || root;

function slug(v) {
  return String(v == null ? '' : v).trim().toLowerCase();
}

const clientSlug     = slug(body.client_slug || 'wolfhouse-somo');
const bookingCode    = String(body.booking_code || '').trim();
const guestPhone     = String(body.guest_phone || '').trim();
const serviceType    = slug(body.service_type || 'wetsuit');
const serviceDate    = String(body.service_date || '').trim();
const quantity       = parseInt(body.quantity, 10) || 1;
const paymentChoice  = slug(body.payment_choice || 'pay_now');
const source         = String(body.source || 'luna_whatsapp').trim();

if (!bookingCode) throw new Error('Missing required field: booking_code');
if (!serviceDate) throw new Error('Missing required field: service_date');

const idempotencyKey = [
  bookingCode,
  serviceType,
  serviceDate,
  String(quantity),
  guestPhone.replace(/\+/g, '')
].join('-').slice(0, 120);

return [{
  json: {
    client_slug: clientSlug,
    booking_code: bookingCode,
    guest_phone: guestPhone,
    service_type: serviceType,
    service_date: serviceDate,
    quantity,
    payment_choice: paymentChoice,
    source,
    idempotency_key: idempotencyKey,
    dry_run: true,
    live_send_enabled: false,
    _dry_run: true
  }
}];

