// Stage 8.8.31 — format guest add-on dry-run reply (never sent on WhatsApp)
const createResp = $input.first().json;
const parsed = $('Code - Parse Guest Addon Request').first().json;
const previewBody = $('HTTP - Bot Addon Preview').first().json;

const checkoutUrl = createResp.checkout_url || null;
let replyDraft = createResp.reply_draft || previewBody.reply_draft || '';

if (!checkoutUrl && createResp.reason === 'meal_on_site_only') {
  replyDraft = replyDraft || 'Meals are handled on site — request recorded without payment link.';
}

return [{
  json: {
    whatsapp_sent: false,
    dry_run: true,
    live_send_blocked: true,
    no_n8n_side_effect: true,
    client_slug: parsed.client_slug,
    booking_code: parsed.booking_code,
    guest_phone: parsed.guest_phone,
    service_type: parsed.service_type,
    service_date: parsed.service_date,
    quantity: parsed.quantity,
    payment_choice: parsed.payment_choice,
    idempotency_key: parsed.idempotency_key,
    preview_next_action: previewBody.next_action,
    create_success: createResp.success === true,
    idempotent: createResp.idempotent === true,
    write_performed: createResp.write_performed,
    service_record_id: createResp.service_record_id || null,
    payment_id: createResp.payment_id || null,
    payment_kind: createResp.payment_kind || null,
    checkout_url: checkoutUrl,
    payment_required: createResp.payment_required,
    reason: createResp.reason || null,
    reply_draft: replyDraft,
    no_payment_truth_recorded: createResp.no_payment_truth_recorded !== false,
    _proof_no_direct_stripe: true,
    _stage: '8.8.31'
  }
}];
